# Extract the assertions from the response
assertions = []
for assertion in response_tree.findall(".//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion"):
    assertions.append(assertion)

# Authenticate the users based on the extracted assertions
for assertion in assertions:
    user_id = assertion.find(".//{urn:oasis:names:tc:SAML:2.0:assertion}NameID").text
